/**
 * @fileoverview DragDrop view — DOM setup / teardown and placeholder management.
 * @module module/DragDrop/view
 */

import razyui from '../../index.js';
import { CLS, ARIA, STYLE, PART } from './constants.js';

// ═══════════════════════════════════════
//  Placeholder
// ═══════════════════════════════════════

/**
 * Create a detached placeholder element.
 * @returns {HTMLDivElement}
 */
export function createPlaceholder() {
    const ph = PART.PLACEHOLDER.create({ [ARIA.HIDDEN]: 'true' });
    return ph[0];
}

/**
 * Size the placeholder to match a reference element's bounding rect.
 * @param {HTMLElement} placeholder
 * @param {HTMLElement} el — element to measure
 */
export function sizeToElement(placeholder, el) {
    const rect = el.getBoundingClientRect();
    razyui(placeholder).css({ width: rect.width + 'px', height: rect.height + 'px' });
}

/**
 * Find the insertion point (the child to insert before) based on pointer
 * position relative to item midpoints.
 *
 * @param {HTMLElement[]} items — candidate siblings
 * @param {string|null} axis   — 'x' | 'y' | null
 * @param {number} clientX
 * @param {number} clientY
 * @returns {HTMLElement|null} — child to insert before, or null for append
 */
export function findInsertionPoint(items, axis, clientX, clientY) {
    for (const child of items) {
        const rect = child.getBoundingClientRect();
        const midY = rect.top  + rect.height / 2;
        const midX = rect.left + rect.width  / 2;

        if (axis === 'x') {
            if (clientX < midX) return child;
        } else {
            if (clientY < midY) return child;
        }
    }
    return null;
}

/**
 * Remove placeholder from the DOM (if attached).
 * @param {HTMLElement|null} placeholder
 */
export function removePlaceholder(placeholder) {
    if (placeholder && placeholder.parentNode) {
        placeholder.remove();
    }
}

// ═══════════════════════════════════════
//  Container marking
// ═══════════════════════════════════════

/**
 * Mark a container element as a DragDrop zone.
 * @param {Elements} container — razyui Elements
 */
export function markContainer(container) {
    container.addClass('drag-drop ' + CLS.CONTAINER);
    PART.CONTAINER.apply(container);
}

/**
 * Remove DragDrop zone marking from a container.
 * @param {Elements} container — razyui Elements
 */
export function unmarkContainer(container) {
    container.removeClass('drag-drop ' + CLS.CONTAINER);
    PART.CONTAINER.unapply(container);
}

// ═══════════════════════════════════════
//  Item styling helpers
// ═══════════════════════════════════════

/**
 * Apply drag-handle styles to a handle element.
 * @param {HTMLElement} handle
 */
export function styleHandle(handle) {
    razyui(handle).css({ cursor: STYLE.CURSOR_GRAB, touchAction: STYLE.TOUCH_NONE });
}

/**
 * Apply draggable styles to an item (when no handle is used).
 * @param {HTMLElement} item
 */
export function styleItem(item) {
    razyui(item).css('touchAction', STYLE.TOUCH_NONE);
}

// ═══════════════════════════════════════
//  Cleanup
// ═══════════════════════════════════════

/**
 * Reset items on destroy — remove draggable attribute and bound flag.
 * @param {HTMLElement[]} items
 */
export function cleanupItems(items) {
    items.forEach(item => {
        razyui(item).removeAttr('draggable');
        item._ddBound = false;
    });
}
