/**
 * @fileoverview DragDrop barrel — re-exports from modular implementation.
 * Kept at module root for backward compatibility with razyui.load().
 *
 * @module module/DragDrop
 */
import { default as razyui } from '../index.js';
import { DragDropDef as DEF } from './DragDrop.def.js';
import DragDrop from './DragDrop/index.js';

// ── Module registration ──
// Register the DragDrop component to the global razyui object
razyui.DragDrop = DragDrop;

// ── JIT Component Definition registration ──
// If the JIT compiler is available, register the component definition
if (razyui.JIT?.defineComponent) {
    razyui.JIT.defineComponent(DEF.name, DEF);
}

// ── Custom Element registration ──
/**
 * Registers the DragDrop component as a custom HTML element.
 * This allows the component to be used directly in HTML via its defined tag.
 *
 * @returns {void}
 */
export function registerElement() {
    const { tag, observedAttrs, attrMap } = DEF.ce;
    
    // Prevent duplicate registration
    if (customElements.get(tag)) return;
    
    // Define the custom element
    customElements.define(tag, class extends HTMLElement {
        /**
         * Specifies which attributes should be observed for changes.
         * @returns {string[]} Array of attribute names to observe.
         */
        static get observedAttributes() { return observedAttrs; }
        
        /**
         * Called when the element is inserted into the DOM.
         * Initializes the DragDrop controller.
         */
        connectedCallback()    { this._ctrl = new DragDrop(this, this.dataset); }
        
        /**
         * Called when the element is removed from the DOM.
         * Cleans up the DragDrop controller.
         */
        disconnectedCallback() { this._ctrl?.destroy?.(); }
        
        /**
         * Called when an observed attribute changes.
         * Updates the corresponding property on the controller.
         *
         * @param {string} n - The name of the attribute that changed.
         * @param {string} o - The old value of the attribute.
         * @param {string} v - The new value of the attribute.
         */
        attributeChangedCallback(n, o, v) {
            if (o !== v && this._ctrl) this._ctrl[attrMap[n]] = v;
        }
        
        /**
         * Gets the underlying DragDrop controller instance.
         * @returns {DragDrop} The DragDrop controller.
         */
        get control() { return this._ctrl; }
    });
}

export default DragDrop;
export const stylesheet = null;
