/**
 * @fileoverview DragDrop component definition for JIT pipeline.
 *
 * Bundles design tokens, state machine config, template slot definitions,
 * and Custom Element metadata.
 *
 * @module module/DragDrop.def
 */

import razyui from '../index.js';
import { PART } from './DragDrop/constants.js';

/**
 * The definition object for the DragDrop component.
 * Contains configuration for tokens, states, templates, and custom elements.
 *
 * @type {Object}
 */
export const DragDropDef = {
    /**
     * The name of the component.
     * @type {string}
     */
    name: 'DragDrop',
    
    /**
     * The custom element tag name for the component.
     * @type {string}
     */
    tag: 'rui-drag-drop',

    // ═══════════════════════════════════════
    //  Design Tokens
    // ═══════════════════════════════════════
    /**
     * Design tokens specific to the DragDrop component.
     * These tokens define the visual appearance of the component.
     */
    tokens: {
        prefix: 'dd',
        tokens: {
            'placeholder-border-width': { value: '2px',       description: 'Placeholder border width' },
            'placeholder-radius':       { ref: 'radius.md',   description: 'Placeholder border radius' },
            'drag-opacity':             { value: '0.35',      description: 'Dragged item opacity' },
            'drop-outline-width':       { value: '2px',       description: 'Drop target outline width' },
            'accent':                   { ref: 'color.accent', description: 'Accent color' },
            'accent-subtle':            { ref: 'color.accent-subtle', description: 'Accent subtle' },
            'border':                   { ref: 'color.border', description: 'Border color' },
        },
    },

    // ═══════════════════════════════════════
    //  State Machine
    // ═══════════════════════════════════════
    /**
     * State machine configuration for the DragDrop component.
     * Defines the possible states and transitions.
     */
    states: {
        initial: 'idle',
        states: {
            idle: {
                on: { DRAG_START: 'dragging' },
            },
            dragging: {
                on: { DROP: 'idle', DRAG_END: 'idle' },
            },
        },
        effects: {
            /**
             * Effect triggered when entering the 'dragging' state.
             * Adds the 'is-dragging' class to the dragged item.
             *
             * @param {Object} ctx - The state context.
             * @param {HTMLElement} ctx.item - The item being dragged.
             */
            dragging(ctx) {
                if (ctx.item) razyui(ctx.item).addClass('is-dragging');
            },
            /**
             * Effect triggered when entering the 'idle' state.
             * Removes the 'is-dragging' class from the item.
             *
             * @param {Object} ctx - The state context.
             * @param {HTMLElement} ctx.item - The item that was dragged.
             */
            idle(ctx) {
                if (ctx.item) razyui(ctx.item).removeClass('is-dragging');
            },
        },
    },

    // ═══════════════════════════════════════
    //  Template Slots
    // ═══════════════════════════════════════
    /**
     * Template slot definitions for the DragDrop component.
     * Defines the HTML structure and classes for different parts of the component.
     */
    template: {
        slots: {
            container:   { element: 'div', classes: ['dd-container'] },
            placeholder: { element: 'div', classes: ['dd-placeholder'] },
        },
    },

    // ═══════════════════════════════════════
    //  JIT Parts
    // ═══════════════════════════════════════
    jitParts: {
        [PART.CONTAINER]: PART.CONTAINER,
        [PART.PLACEHOLDER]: PART.PLACEHOLDER,
    },

    styles: {},

    // ═══════════════════════════════════════
    //  Custom Element
    // ═══════════════════════════════════════
    observedAttrs: ['group', 'handle', 'disabled'],
    attrMap: {
        group:    'group',
        handle:   'handle',
        disabled: 'disabled',
    },
};

export default DragDropDef;
